const VOICE_LOCAL_AUDIO_GATE_MIN_SNR_DB_NOISY = 8.5;
const VOICE_LOCAL_AUDIO_GATE_MIN_DURATION_MS = 320;
const VOICE_LOCAL_AUDIO_GATE_MIN_DURATION_MS_NOISY = 440;
const VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SPEECH_PROBABILITY = 0.42;
const VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SPEECH_PROBABILITY_NOISY = 0.56;
const VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SNR_DB = 7;
const VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SNR_DB_NOISY = 10.5;
const VOICE_SESSION_SPEAKER_MATCH_DISTANCE = 0.42;
const VOICE_SESSION_SPEAKER_MAX_PROFILES = 3;
const HELIX_CONTEXT_CAPSULE_MAX_IDS = 12;
const HELIX_CONTEXT_CAPSULE_AUTO_APPLY_IDS_VOICE = HELIX_CONTEXT_CAPSULE_MAX_IDS;
const HELIX_CONTEXT_CAPSULE_AUTO_APPLY_IDS_MANUAL = HELIX_CONTEXT_CAPSULE_MAX_IDS;
const HELIX_VOICE_AUTO_SPEAK_DEFAULT_PROFILE_ID = "vU0dJF9WOwsWEUfX1Aqw";
const HELIX_VOICE_AUTO_SPEAK_PROVIDER = "elevenlabs";
const HELIX_VOICE_AUTO_SPEAK_QUEUE_MAX = 8;
const HELIX_VOICE_AUTO_SPEAK_TEXT_MAX_CHARS = 2400;
const HELIX_VOICE_DEBUG_TIMELINE_LIMIT = 280;
const HELIX_TIMELINE_TYPE_LABEL: Record<HelixTimelineEntryType, string> = {
  conversation_recorded: "recorded",
  conversation_brief: "brief",
  reasoning_attempt: "reasoning",
  reasoning_stream: "stream",
  reasoning_final: "final",
  action_receipt: "action",
  suppressed: "suppressed",
};

const SESSION_CAPSULE_CONFIDENCE_LABEL: Record<SessionCapsuleConfidenceBand, string> = {
  reinforcing: "reinforcing",
  building: "building",
  uncertain: "uncertain",
};

type VoiceNoiseHandlingProfile = {
  bargeStartMsDesktop: number;
  bargeStartMsMobile: number;
  bargeMinSpeechProbability: number;
  bargeStrongSpeechProbability: number;
  bargeMinSnrDb: number;
  bargeRmsMultiplier: number;
  localGateMinSpeechProbability: number;
  localGateMinSnrDb: number;
  localGateMinDurationMs: number;
  localGateLowQualitySpeechProbability: number;
  localGateLowQualitySnrDb: number;
};

export function resolveVoiceNoiseHandlingProfile(noisyEnvironmentMode: boolean): VoiceNoiseHandlingProfile {
  if (noisyEnvironmentMode) {
    return {
      bargeStartMsDesktop: MIC_PLAYBACK_BARGE_START_MS_DESKTOP_NOISY,
      bargeStartMsMobile: MIC_PLAYBACK_BARGE_START_MS_MOBILE_NOISY,
      bargeMinSpeechProbability: MIC_PLAYBACK_BARGE_MIN_SPEECH_PROBABILITY_NOISY,
      bargeStrongSpeechProbability: MIC_PLAYBACK_BARGE_STRONG_SPEECH_PROBABILITY_NOISY,
      bargeMinSnrDb: MIC_PLAYBACK_BARGE_MIN_SNR_DB_NOISY,
      bargeRmsMultiplier: MIC_PLAYBACK_BARGE_RMS_MULTIPLIER_NOISY,
      localGateMinSpeechProbability: VOICE_LOCAL_AUDIO_GATE_MIN_SPEECH_PROBABILITY_NOISY,
      localGateMinSnrDb: VOICE_LOCAL_AUDIO_GATE_MIN_SNR_DB_NOISY,
      localGateMinDurationMs: VOICE_LOCAL_AUDIO_GATE_MIN_DURATION_MS_NOISY,
      localGateLowQualitySpeechProbability: VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SPEECH_PROBABILITY_NOISY,
      localGateLowQualitySnrDb: VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SNR_DB_NOISY,
    };
  }
  return {
    bargeStartMsDesktop: MIC_PLAYBACK_BARGE_START_MS_DESKTOP,
    bargeStartMsMobile: MIC_PLAYBACK_BARGE_START_MS_MOBILE,
    bargeMinSpeechProbability: MIC_PLAYBACK_BARGE_MIN_SPEECH_PROBABILITY,
    bargeStrongSpeechProbability: MIC_PLAYBACK_BARGE_STRONG_SPEECH_PROBABILITY,
    bargeMinSnrDb: MIC_PLAYBACK_BARGE_MIN_SNR_DB,
    bargeRmsMultiplier: MIC_PLAYBACK_BARGE_RMS_MULTIPLIER,
    localGateMinSpeechProbability: VOICE_LOCAL_AUDIO_GATE_MIN_SPEECH_PROBABILITY,
    localGateMinSnrDb: VOICE_LOCAL_AUDIO_GATE_MIN_SNR_DB,
    localGateMinDurationMs: VOICE_LOCAL_AUDIO_GATE_MIN_DURATION_MS,
    localGateLowQualitySpeechProbability: VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SPEECH_PROBABILITY,
    localGateLowQualitySnrDb: VOICE_LOCAL_AUDIO_GATE_LOW_QUALITY_SNR_DB,
  };
}

function isLowAudioQualitySignal(args: {
  speechProbability: number | null | undefined;
  snrDb: number | null | undefined;
  lowQualitySpeechProbability: number;
  lowQualitySnrDb: number;
}): boolean {
  return (
    (typeof args.speechProbability === "number" &&
      args.speechProbability < args.lowQualitySpeechProbability) ||
    (typeof args.snrDb === "number" && args.snrDb < args.lowQualitySnrDb)
  );
}

function createVoiceCaptureCheckpointMap(): Record<VoiceCaptureCheckpointKey, VoiceCaptureCheckpoint> {
  return VOICE_CAPTURE_CHECKPOINT_ORDER.reduce(
    (acc, key) => {
      acc[key] = {
        key,
        status: "idle",
        message: null,
        lastAtMs: null,
        latencyMs: null,
      };
      return acc;
    },
    {} as Record<VoiceCaptureCheckpointKey, VoiceCaptureCheckpoint>,
  );
}

const CONTEXT_CAPSULE_PROOF_POSTURE_SCORE: Record<ContextCapsuleConvergence["proofPosture"], number> = {
  confirmed: 5,
  reasoned: 4,
  hypothesis: 3,
  unknown: 2,
  fail_closed: 1,
};

const CONTEXT_CAPSULE_MATURITY_SCORE: Record<ContextCapsuleConvergence["maturity"], number> = {
  certified: 4,
  diagnostic: 3,
  reduced_order: 2,
  exploratory: 1,
};

const CONTEXT_CAPSULE_PROOF_VERDICT_SCORE: Record<ContextCapsuleSummary["commit"]["proof_verdict"], number> = {
  PASS: 3,
  UNKNOWN: 2,
  FAIL: 1,
};

function resolveSessionCapsuleConfidenceBand(
  summary: ContextCapsuleSummary,
): SessionCapsuleConfidenceBand {
  if (
    summary.convergence.proofPosture === "fail_closed" ||
    summary.commit.proof_verdict === "FAIL" ||
    summary.commit.certificate_integrity_ok === false
  ) {
    return "uncertain";
  }
  if (summary.convergence.proofPosture === "confirmed") {
    return "reinforcing";
  }
  if (
    summary.convergence.proofPosture === "reasoned" &&
    (summary.commit.proof_verdict === "PASS" || summary.convergence.maturity === "certified")
  ) {
    return "reinforcing";
  }
  if (
    summary.convergence.proofPosture === "reasoned" ||
    summary.convergence.proofPosture === "hypothesis" ||
    summary.convergence.maturity === "diagnostic" ||
    summary.convergence.maturity === "certified"
  ) {
    return "building";
  }
  return "uncertain";
}

export function deriveSessionCapsuleState(
  entries: ContextCapsuleLedgerEntry[],
): SessionCapsuleState | null {
  if (!Array.isArray(entries) || entries.length === 0) return null;
  const latest = [...entries].sort((a, b) => {
    const touchedDelta = b.touchedAtMs - a.touchedAtMs;
    if (touchedDelta !== 0) return touchedDelta;
    const createdDelta = b.summary.createdAtTsMs - a.summary.createdAtTsMs;
    if (createdDelta !== 0) return createdDelta;
    return a.id.localeCompare(b.id);
  })[0];
  return {
    id: latest.id,
    summary: latest.summary,
    confidenceBand: resolveSessionCapsuleConfidenceBand(latest.summary),
  };
}

function resolveContextCapsuleLedgerId(
  summary: Pick<ContextCapsuleSummary, "fingerprint" | "capsuleId">,
): string | null {
  return (
    normalizeContextCapsuleId(summary.fingerprint) ??
    normalizeContextCapsuleId(summary.capsuleId)
  );
}

export function compareContextCapsuleSummariesByRank(
  a: ContextCapsuleSummary,
  b: ContextCapsuleSummary,
): number {
  const proofPostureDelta =
    CONTEXT_CAPSULE_PROOF_POSTURE_SCORE[b.convergence.proofPosture] -
    CONTEXT_CAPSULE_PROOF_POSTURE_SCORE[a.convergence.proofPosture];
  if (proofPostureDelta !== 0) return proofPostureDelta;

  const maturityDelta =
    CONTEXT_CAPSULE_MATURITY_SCORE[b.convergence.maturity] -
    CONTEXT_CAPSULE_MATURITY_SCORE[a.convergence.maturity];
  if (maturityDelta !== 0) return maturityDelta;

  const proofVerdictDelta =
    CONTEXT_CAPSULE_PROOF_VERDICT_SCORE[b.commit.proof_verdict] -
    CONTEXT_CAPSULE_PROOF_VERDICT_SCORE[a.commit.proof_verdict];
  if (proofVerdictDelta !== 0) return proofVerdictDelta;

  const integrityScoreA =
    a.commit.certificate_integrity_ok === true ? 2 : a.commit.certificate_integrity_ok === false ? 0 : 1;
  const integrityScoreB =
    b.commit.certificate_integrity_ok === true ? 2 : b.commit.certificate_integrity_ok === false ? 0 : 1;
  const integrityDelta = integrityScoreB - integrityScoreA;
  if (integrityDelta !== 0) return integrityDelta;

  const createdAtDelta = b.createdAtTsMs - a.createdAtTsMs;
  if (createdAtDelta !== 0) return createdAtDelta;

  return a.fingerprint.localeCompare(b.fingerprint);
}

function compareContextCapsuleLedgerEntriesByRank(
  a: ContextCapsuleLedgerEntry,
  b: ContextCapsuleLedgerEntry,
): number {
  if (a.pinned !== b.pinned) {
    return a.pinned ? -1 : 1;
  }
  return compareContextCapsuleSummariesByRank(a.summary, b.summary);
}

function compareContextCapsuleLedgerEntriesForSelection(
  a: ContextCapsuleLedgerEntry,
  b: ContextCapsuleLedgerEntry,
): number {
  if (a.pinned !== b.pinned) {
    return a.pinned ? -1 : 1;
  }
  const touchedDelta = b.touchedAtMs - a.touchedAtMs;
  if (touchedDelta !== 0) return touchedDelta;
  if (a.pinnedAtMs !== b.pinnedAtMs) {
    return (b.pinnedAtMs ?? 0) - (a.pinnedAtMs ?? 0);
  }
  return compareContextCapsuleSummariesByRank(a.summary, b.summary);
}

export function upsertContextCapsuleLedger(args: {
  entries: ContextCapsuleLedgerEntry[];
  summary: ContextCapsuleSummary;
  pin?: boolean;
  maxEntries?: number;
  nowMs?: number;
}): ContextCapsuleLedgerEntry[] {
  const maxEntries = Math.max(
    1,
    Math.min(args.maxEntries ?? HELIX_CONTEXT_CAPSULE_MAX_IDS, HELIX_CONTEXT_CAPSULE_MAX_IDS),
  );
  const nowMs = args.nowMs ?? Date.now();
  const capsuleId = resolveContextCapsuleLedgerId(args.summary);
  if (!capsuleId) {
    return [...args.entries].sort(compareContextCapsuleLedgerEntriesByRank).slice(0, maxEntries);
  }

  const existingIndex = args.entries.findIndex((entry) => entry.id === capsuleId);
  const pin = args.pin === true;
  const nextEntries = [...args.entries];
  if (existingIndex >= 0) {
    const existing = nextEntries[existingIndex];
    nextEntries[existingIndex] = {
      ...existing,
      summary: args.summary,
      pinned: existing.pinned || pin,
      pinnedAtMs: existing.pinnedAtMs ?? (pin ? nowMs : null),
      touchedAtMs: nowMs,
    };
  } else {
    nextEntries.push({
      id: capsuleId,
      summary: args.summary,
      pinned: pin,
      pinnedAtMs: pin ? nowMs : null,
      touchedAtMs: nowMs,
    });
  }

  while (nextEntries.length > maxEntries) {
    const evictionPool = nextEntries.some((entry) => !entry.pinned)
      ? nextEntries.filter((entry) => !entry.pinned)
      : nextEntries;
    const lowest = [...evictionPool]
      .sort((a, b) => compareContextCapsuleSummariesByRank(a.summary, b.summary))
      .at(-1);
    if (!lowest) break;
    const dropIndex = nextEntries.findIndex((entry) => entry.id === lowest.id);
    if (dropIndex < 0) break;
    nextEntries.splice(dropIndex, 1);
  }

  return nextEntries.sort(compareContextCapsuleLedgerEntriesByRank).slice(0, maxEntries);
}

export function buildSelectedContextCapsuleIds(args: {
  ledgerEntries: ContextCapsuleLedgerEntry[];
  prompt?: string;
  inlineCapsuleIds?: string[];
  maxIds?: number;
}): string[] {
  const maxIds = Math.max(
    1,
    Math.min(args.maxIds ?? HELIX_CONTEXT_CAPSULE_MAX_IDS, HELIX_CONTEXT_CAPSULE_MAX_IDS),
  );
  const seen = new Set<string>();
  const out: string[] = [];
  const push = (value: string | null | undefined) => {
    const normalized = normalizeContextCapsuleId(value ?? null);
    if (!normalized || seen.has(normalized)) return;
    seen.add(normalized);
    out.push(normalized);
  };

  const inlineIds = args.inlineCapsuleIds ?? extractContextCapsuleIdsFromText(args.prompt ?? "");
  for (const inlineId of inlineIds) {
    push(inlineId);
    if (out.length >= maxIds) return out;
  }

  const orderedLedger = [...args.ledgerEntries].sort(compareContextCapsuleLedgerEntriesForSelection);
  for (const entry of orderedLedger) {
    push(entry.id);
    if (out.length >= maxIds) return out;
  }

  return out;
}

export function buildLatestWinsContextCapsuleIds(args: {
  ledgerEntries: ContextCapsuleLedgerEntry[];
  prompt?: string;
  inlineCapsuleIds?: string[];
  maxIds?: number;
}): string[] {
  const maxIds = Math.max(
    1,
    Math.min(args.maxIds ?? HELIX_CONTEXT_CAPSULE_MAX_IDS, HELIX_CONTEXT_CAPSULE_MAX_IDS),
  );
  const inlineIds = args.inlineCapsuleIds ?? extractContextCapsuleIdsFromText(args.prompt ?? "");
  const seen = new Set<string>();
  const out: string[] = [];
  const push = (value: string | null | undefined) => {
    const normalized = normalizeContextCapsuleId(value ?? null);
    if (!normalized || seen.has(normalized)) return;
    seen.add(normalized);
    out.push(normalized);
  };
  for (const inlineId of inlineIds) {
    push(inlineId);
    if (out.length >= maxIds) return out;
  }
  const recencySorted = [...args.ledgerEntries].sort(compareContextCapsuleLedgerEntriesForSelection);
  const confidenceSorted = [...args.ledgerEntries].sort(compareContextCapsuleLedgerEntriesByRank);
  let recencyIndex = 0;
  let confidenceIndex = 0;
  while (out.length < maxIds && (recencyIndex < recencySorted.length || confidenceIndex < confidenceSorted.length)) {
    for (let step = 0; step < 2 && recencyIndex < recencySorted.length && out.length < maxIds; step += 1) {
      push(recencySorted[recencyIndex]?.id);
      recencyIndex += 1;
    }
    if (confidenceIndex < confidenceSorted.length && out.length < maxIds) {
      push(confidenceSorted[confidenceIndex]?.id);
      confidenceIndex += 1;
    }
  }
  return out.slice(0, maxIds);
}

export function smoothVoiceLevel(
  previous: number,
  nextRaw: number,
  attack = VOICE_LEVEL_ATTACK_ALPHA,
  release = VOICE_LEVEL_RELEASE_ALPHA,
): number {
  const prev = clamp01(previous);
  const next = clamp01(nextRaw);
  const alpha = clampNumber(next >= prev ? attack : release, 0, 1);
  return clamp01(prev + (next - prev) * alpha);
}

export function isFlatVoiceSignal(
  variance: number,
  elapsedMs: number,
  threshold = VOICE_FLAT_SIGNAL_VARIANCE_THRESHOLD,
  windowMs = VOICE_FLAT_SIGNAL_WINDOW_MS,
): boolean {
  return variance <= threshold && elapsedMs >= windowMs;
}

export function isRecorderStalled(params: {
  recorderActive: boolean;
  nowMs: number;
  recorderStartedAtMs: number | null;
  lastChunkAtMs: number | null;
  stallMs?: number;
}): boolean {
  const stallMs = params.stallMs ?? VOICE_RECORDER_STALL_MS;
  if (!params.recorderActive) return false;
  const referenceMs = params.lastChunkAtMs ?? params.recorderStartedAtMs;
  if (referenceMs === null) return false;
  return params.nowMs - referenceMs >= stallMs;
}

export function isLikelyLoopbackDeviceLabel(label: string): boolean {
  return /\b(output|loopback|stereo mix|vb-audio|voicemeeter|what u hear)\b/i.test(label.trim());
}

export function shouldPrimeSegmentWithContainerHeader(params: {
  segmentStartIndex: number;
  mimeType?: string | null;
  hasHeaderChunk: boolean;
}): boolean {
  if (!params.hasHeaderChunk) return false;
  if (params.segmentStartIndex <= 0) return false;
  const normalized = (params.mimeType ?? "").trim().toLowerCase();
  if (!normalized) return false;
  // WebM/Ogg slices can lose container init data and benefit from header priming.
  // MP4-family slices are more fragile when concatenated with a primed header.
  return normalized.includes("webm") || normalized.includes("ogg");
}

export function getMicRecorderMimeCandidates(userAgent?: string): string[] {
  const ua =
    (userAgent ?? (typeof navigator !== "undefined" ? navigator.userAgent : ""))
      .trim()
      .toLowerCase();
  const iosLike = IOS_AUDIO_USER_AGENT_PATTERN.test(ua) || isLikelyIOSDesktopModeUserAgent(ua);
  const ordered = iosLike
    ? [
        "audio/mp4;codecs=mp4a.40.2",
        "audio/mp4",
        "audio/webm;codecs=opus",
        "audio/webm",
        "audio/ogg;codecs=opus",
      ]
    : [
        "audio/webm;codecs=opus",
        "audio/webm",
        "audio/ogg;codecs=opus",
        "audio/mp4",
      ];
  return [...new Set(ordered)];
}

export function pickSupportedMicRecorderMimeType(params: {
  userAgent?: string;
  isTypeSupported: (mimeType: string) => boolean;
}): string | undefined {
  const candidates = getMicRecorderMimeCandidates(params.userAgent);
  for (const mimeType of candidates) {
    try {
      if (params.isTypeSupported(mimeType)) {
        return mimeType;
      }
    } catch {
      // continue checking the next mime type
    }
  }
  return undefined;
}

function pickMicRecorderMimeType(): string | undefined {
  if (typeof MediaRecorder === "undefined" || typeof MediaRecorder.isTypeSupported !== "function") {
    return undefined;
  }
  const userAgent = typeof navigator !== "undefined" ? navigator.userAgent : undefined;
  return pickSupportedMicRecorderMimeType({
    userAgent,
    isTypeSupported: MediaRecorder.isTypeSupported.bind(MediaRecorder),
  });
}

export function inferAskMode(question: string): "observe" | "act" | "verify" | undefined {
  const normalized = question.trim().toLowerCase();
  if (!normalized) return undefined;

  if (
    /\b(verify|verification|prove|proof|validate|validation|integrity|certificate|pass\/fail|pass fail|audit|check)\b/.test(
      normalized,
    )
  ) {
    return "verify";
  }

  if (
    /^(please\s+)?(implement|fix|change|update|remove|add|create|open|start|stop|run|patch|rewrite)\b/.test(
      normalized,
    ) ||
    /\b(next action|take action|fix this|implement this|make this|change this|update this)\b/.test(
      normalized,
    )
  ) {
    return "act";
  }

  if (
    /\b(observe|monitor|watch|track|status|state|what changed|what is happening|inspect|summarize the current)\b/.test(
      normalized,
    )
  ) {
    return "observe";
  }

  return undefined;
}

export function mergeVoiceTranscriptDraft(currentDraft: string, transcript: string): string {
  const normalizedSegment = transcript
    .trim()
    .replace(/^\.\.\.\s*/, "")
    .replace(/\s*\.\.\.$/, "");
  if (!normalizedSegment) return currentDraft;
  const normalizedDraft = currentDraft.trimEnd().replace(/\s*\.\.\.$/, "");
  if (!normalizedDraft) return normalizedSegment;
  const lowerDraft = normalizedDraft.toLowerCase();
  const lowerSegment = normalizedSegment.toLowerCase();
  if (lowerSegment === lowerDraft) return normalizedDraft;
  // STT can return cumulative text for later chunks; treat it as authoritative.
  if (lowerSegment.startsWith(lowerDraft)) return normalizedSegment;
  if (lowerDraft.startsWith(lowerSegment)) return normalizedDraft;
  const maxOverlap = Math.min(lowerDraft.length, lowerSegment.length);
  // Find longest exact suffix/prefix overlap to avoid duplicate seam text.
  for (let overlap = maxOverlap; overlap >= 5; overlap -= 1) {
    if (!lowerDraft.endsWith(lowerSegment.slice(0, overlap))) continue;
    const overlapText = lowerSegment.slice(0, overlap).trim();
    const overlapWordCount = overlapText ? overlapText.split(/\s+/).filter(Boolean).length : 0;
    if (overlapWordCount < 2 && overlap < 10) continue;
    const remainder = normalizedSegment.slice(overlap).trimStart();
    return remainder.length > 0 ? `${normalizedDraft} ${remainder}` : normalizedDraft;
  }
  const joiner = normalizedDraft && !/\s$/.test(normalizedDraft) ? " " : "";
  return `${normalizedDraft}${joiner}${normalizedSegment}`;
}

export function shouldMergeVoiceContinuationTurn(args: {
  previousPrompt: string;
  nextTranscript: string;
  gapMs: number;
  windowMs?: number;
}): boolean {
  const windowMs = args.windowMs ?? VOICE_CONTINUATION_MERGE_WINDOW_MS;
  if (args.gapMs < 0 || args.gapMs > windowMs) return false;
  const previous = args.previousPrompt.trim();
  const next = args.nextTranscript.trim();
  if (!previous || !next) return false;
  const nextWords = next.split(/\s+/).filter(Boolean);
  const nextStartsContinuation =
    /^[a-z]/.test(next) ||
    /^(and|but|so|then|because|which|that|who|where|when|while|if|with|for|to|used|using)\b/i.test(
      next,
    );
  if (nextStartsContinuation) return true;
  const previousLooksIncomplete = !/[.!?]["')\]]?\s*$/.test(previous);
  return previousLooksIncomplete && nextWords.length <= VOICE_CONTINUATION_SHORT_WORD_LIMIT;
}

export function shouldMergeVoiceContinuationInFlight(args: {
  gapMs: number;
  lexicalContinuation: boolean;
  activeWindowMs?: number;
}): boolean {
  const activeWindowMs = args.activeWindowMs ?? VOICE_CONTINUATION_ACTIVE_CHAIN_WINDOW_MS;
  if (args.gapMs < 0) return false;
  if (args.gapMs <= activeWindowMs) return true;
  return args.lexicalContinuation;
}

export function shouldRestartExplorationLadderOnSupersede(args: {
  hasContinuityCandidate: boolean;
  forceTailContinuationMerge: boolean;
  shortContinuationAddendum: boolean;
  canMergeContinuation: boolean;
  intentShiftBand: IntentShiftBand;
}): boolean {
  if (!args.hasContinuityCandidate) return false;
  if (args.forceTailContinuationMerge || args.shortContinuationAddendum) return false;
  if (args.canMergeContinuation && args.intentShiftBand === "continuation") return false;
  return true;
}

export function hasDanglingTurnTail(transcript: string): boolean {
  const normalized = transcript.trim().toLowerCase().replace(/[.!?]+$/g, "").trim();
  if (!normalized) return false;
  return /\b(and|or|but|so|because|that|which|who|when|where|why|what|how|if|to|of|for|with|in|on|at|from|is|are|was|were|be|been|being|the|a|an|it|this|these|those|my|your|our|their|does|do|did|can|could|would|will)\s*$/.test(
    normalized,
  );
}

export function isLowInformationTailTranscript(transcript: string): boolean {
  const normalized = transcript.trim().toLowerCase().replace(/^[^a-z0-9]+|[^a-z0-9]+$/g, "");
  if (!normalized) return true;
  const words = normalized.split(/\s+/).filter(Boolean);
  if (words.length > 3) return false;
  if (/\b(verify|check|prove|fix|implement|change|update|explain|define|what|why|how)\b/.test(normalized)) {
    return false;
  }
  const compact = words.join("");
  return compact.length <= 18;
}

export function shouldIgnoreLowQualityTranscriptBargeIn(args: {
  lowAudioQuality: boolean;
  confidence: number;
  speechProbability: number | null | undefined;
  snrDb: number | null | undefined;
  hasActiveVoiceReasoningAttempt: boolean;
  hasActiveVoicePlayback: boolean;
  needsConfirmation: boolean;
}): boolean {
  if (!args.lowAudioQuality) return false;
  if (args.needsConfirmation) return false;
  if (!(args.hasActiveVoiceReasoningAttempt || args.hasActiveVoicePlayback)) return false;
  const hasQualityTelemetry =
    typeof args.speechProbability === "number" || typeof args.snrDb === "number";
  const confidenceThreshold = hasQualityTelemetry
    ? Math.max(0.82, VOICE_STT_CONFIRM_THRESHOLD + 0.12)
    : Math.max(0.9, VOICE_STT_CONFIRM_THRESHOLD + 0.18);
  return args.confidence < confidenceThreshold;
}

export function isLikelyContinuationAddendum(transcript: string): boolean {
  const normalized = transcript.trim().toLowerCase();
  if (!normalized) return false;
  const words = normalized.split(/\s+/).filter(Boolean);
  if (words.length > VOICE_CONTINUATION_ADDENDUM_WORD_LIMIT) return false;
  return /^(and|so|but|then|because|which|that|also|plus|right|yeah|yes|well)\b/.test(normalized);
}

export function isLikelyContinuationTailFragment(transcript: string): boolean {
  const trimmed = transcript.trim();
  if (!trimmed) return false;
  const normalized = trimmed.toLowerCase();
  const words = normalized.split(/\s+/).filter(Boolean);
  if (words.length === 0 || words.length > 14) return false;
  if (/[?]$/.test(trimmed)) return false;
  if (
    /^(what|why|how|when|where|who|which|can|could|would|should|do|does|did|is|are|was|were|explain|define|describe)\b/.test(
      normalized,
    )
  ) {
    return false;
  }
  const startsLower = /^[a-z]/.test(trimmed);
  if (!startsLower) return false;
  return /\b(this|that|it|they|them|those|these|happens?|effect|result|probability|because|within)\b/.test(
    normalized,
  );
}

export function extractLatestContinuationQuestionFocus(transcript: string): string | null {
  const normalized = transcript.replace(/\s+/g, " ").trim();
  if (!normalized) return null;
  const sentences = normalized
    .split(/(?<=[.!?])\s+/)
    .map((entry) => entry.trim())
    .filter(Boolean);
  if (sentences.length < 2) return null;
  const last = sentences[sentences.length - 1] ?? "";
  if (!last) return null;
  const lowered = last.toLowerCase();
  const looksQuestionPivot =
    /^(?:so|and|right|okay|ok|well)[,\s]+/.test(lowered) ||
    /^(?:what about|how about|can you|could you|would you|please)\b/.test(lowered) ||
    /\?$/.test(last);
  if (!looksQuestionPivot) return null;
  const hasIntentVerb = /\b(?:what about|how about|explain|define|relate|compare|tell|walk me through|can you)\b/.test(
    lowered,
  );
  if (!hasIntentVerb && !/\?$/.test(last)) return null;
  if (last.length < 12) return null;
  return clipText(last, 360);
}

export type VoiceBargeHardCutReason =
  | "speech_persisted"
  | "stt_queue"
  | "stt_busy"
  | "pending_confirmation";

export function resolveVoiceBargeHardCutReason(args: {
  holdActive: boolean;
  holdStartedAtMs: number | null;
  nowMs: number;
  transcribeQueueLength: number;
  transcribeBusy: boolean;
  pendingConfirmation: boolean;
  speechActive: boolean;
  persistMs?: number;
}): VoiceBargeHardCutReason | null {
  if (!args.holdActive) return null;
  if (args.pendingConfirmation) return "pending_confirmation";
  // Only escalate to an STT-queue hard cut while speech is actively present.
  // Queue growth by itself can happen during normal segment rollover and should
  // not suppress upcoming brief playback.
  if (args.transcribeQueueLength > 0 && args.speechActive) return "stt_queue";
  if (args.transcribeBusy) return "stt_busy";
  const persistMs = args.persistMs ?? VOICE_BARGE_HARD_CUT_PERSIST_MS;
  if (
    args.speechActive &&
    args.holdStartedAtMs !== null &&
    args.nowMs - args.holdStartedAtMs >= Math.max(0, persistMs)
  ) {
    return "speech_persisted";
  }
  return null;
}

export function shouldResumeBargeHeldPlayback(args: {
  holdActive: boolean;
  resumeNotBeforeMs: number | null;
  nowMs: number;
  transcribeQueueLength: number;
  transcribeBusy: boolean;
  pendingConfirmation: boolean;
  speechActive: boolean;
  micArmed: boolean;
  segmentFlushPending: boolean;
  trafficQuietUntilMs: number | null;
}): boolean {
  if (!args.holdActive) return false;
  if (args.resumeNotBeforeMs === null || args.nowMs < args.resumeNotBeforeMs) return false;
  if (args.transcribeBusy || args.transcribeQueueLength > 0 || args.pendingConfirmation) return false;
  if (args.speechActive || !args.micArmed || args.segmentFlushPending) return false;
  if (args.trafficQuietUntilMs !== null && args.nowMs < args.trafficQuietUntilMs) return false;
  return true;
}

export function shouldTreatMicSignalAsSpeech(args: {
  speakingNow: boolean;
  voiceOutputActive: boolean;
  localAudioGateActive: boolean;
  speechProbability: number;
  snrDb: number;
  rms: number;
  speechTriggerThreshold: number;
  bargeMinSpeechProbability?: number;
  bargeStrongSpeechProbability?: number;
  bargeMinSnrDb?: number;
  bargeRmsMultiplier?: number;
}): boolean {
  if (!args.speakingNow) return false;
  if (!args.voiceOutputActive || !args.localAudioGateActive) return true;
  const threshold = Math.max(args.speechTriggerThreshold, MIC_LEVEL_MIN_THRESHOLD);
  const bargeMinSpeechProbability = args.bargeMinSpeechProbability ?? MIC_PLAYBACK_BARGE_MIN_SPEECH_PROBABILITY;
  const bargeStrongSpeechProbability =
    args.bargeStrongSpeechProbability ?? MIC_PLAYBACK_BARGE_STRONG_SPEECH_PROBABILITY;
  const bargeMinSnrDb = args.bargeMinSnrDb ?? MIC_PLAYBACK_BARGE_MIN_SNR_DB;
  const bargeRmsMultiplier = args.bargeRmsMultiplier ?? MIC_PLAYBACK_BARGE_RMS_MULTIPLIER;
  const highProbability = args.speechProbability >= bargeMinSpeechProbability;
  const decisiveProbability = args.speechProbability >= bargeStrongSpeechProbability;
  const highSnr = args.snrDb >= bargeMinSnrDb;
  const strongAmplitude = args.rms >= threshold * bargeRmsMultiplier;
  const signalCount = Number(highProbability) + Number(highSnr) + Number(strongAmplitude);
  return decisiveProbability || signalCount >= 2;
}

export function shouldRecoverHeldTranscriptAfterNoTranscript(args: {
  heldTranscript: string;
  turnCompleteBand: TurnCompleteScore["band"];
  transcribeQueueLength: number;
  speechActive: boolean;
  sinceLastSpeechMs: number;
}): boolean {
  const held = args.heldTranscript.trim();
  if (!held) return false;
  if (isLowInformationTailTranscript(held)) return false;
  if (args.transcribeQueueLength > 0) return false;
  if (args.speechActive) return false;
  if (args.turnCompleteBand === "high" && args.sinceLastSpeechMs >= VOICE_TURN_CLOSE_SILENCE_MS) {
    return true;
  }
  if (
    args.turnCompleteBand === "medium" &&
    !hasDanglingTurnTail(held) &&
    args.sinceLastSpeechMs >= VOICE_TURN_CLOSE_SILENCE_MS
  ) {
    return true;
  }
  return false;
}

export function shouldFlushHeldTranscriptFromWatchdog(args: {
  heldTranscript: string;
  holdReason: HeldTranscriptReason;
  transcribeQueueLength: number;
  speechActive: boolean;
  transcribeBusy: boolean;
  pendingConfirmation: boolean;
  sinceLastSpeechMs: number;
  ageMs: number;
}): boolean {
  const held = args.heldTranscript.trim();
  if (!held) return false;
  if (args.holdReason !== "continuation_hold") return false;
  if (args.ageMs < VOICE_HELD_TRANSCRIPT_FLUSH_MS) return false;
  if (args.ageMs > VOICE_HELD_TRANSCRIPT_MAX_AGE_MS) return false;
  if (args.transcribeQueueLength > 0) return false;
  if (args.speechActive || args.transcribeBusy || args.pendingConfirmation) return false;
  const turnComplete = scoreVoiceTurnComplete({
    transcript: held,
    pauseMs: Math.max(args.sinceLastSpeechMs, MIC_END_TURN_MS),
    stability: 0.92,
  });
  return shouldRecoverHeldTranscriptAfterNoTranscript({
    heldTranscript: held,
    turnCompleteBand: turnComplete.band,
    transcribeQueueLength: args.transcribeQueueLength,
    speechActive: args.speechActive,
    sinceLastSpeechMs: args.sinceLastSpeechMs,
  });
}

export function evaluateVoiceTurnSealGate(args: {
  sinceLastSpeechMs: number;
  sttQueueDepth: number;
  sttInFlight: boolean;
  heldPending: boolean;
  hashStableDwellMs: number;
  closeSilenceMs?: number;
  hashStableMs?: number;
}): boolean {
  const closeSilenceMs = args.closeSilenceMs ?? VOICE_TURN_CLOSE_SILENCE_MS;
  const hashStableMs = args.hashStableMs ?? VOICE_TURN_HASH_STABLE_DWELL_MS;
  return (
    args.sinceLastSpeechMs >= closeSilenceMs &&
    args.sttQueueDepth <= 0 &&
    !args.sttInFlight &&
    !args.heldPending &&
    args.hashStableDwellMs >= hashStableMs
  );
}

export function scoreConversationCompletion(input: {
  transcript: string;
  pauseMs: number;
  stability: number;
}): CompletionScore {
  const text = input.transcript.trim();
  const stability = Math.max(0, Math.min(1, input.stability));
  let score = 0.2 + stability * 0.45;
  if (/[.!?]$/.test(text)) score += 0.18;
  if (/\b(and|but|or|because|so)\s*$/i.test(text)) score -= 0.16;
  if (/\b(this|that|it|they|those|these)\b/i.test(text) && !/\b(is|are|means|does)\b/i.test(text)) {
    score -= 0.08;
  }
  if (input.pauseMs >= MIC_SOFT_PAUSE_MS) score += 0.06;
  if (input.pauseMs >= MIC_END_TURN_MS) score += 0.12;
  score = Math.max(0, Math.min(1, score));
  if (score < 0.45) return { score, route: "ask_more" };
  if (score < 0.75) return { score, route: "mirror_clarify" };
  return { score, route: "answer" };
}

export function deriveTranscriptConfidence(args: {
  transcript: string;
  providerConfidence?: number | null;
  segments?: Array<{ confidence?: number }>;
}): { confidence: number; reason: string } {
  const provider = typeof args.providerConfidence === "number" && Number.isFinite(args.providerConfidence)
    ? clamp01(args.providerConfidence)
    : null;
  if (provider !== null) {
    return { confidence: provider, reason: "provider_reported" };
  }
  const segmentConfidenceValues = (args.segments ?? [])
    .map((segment) =>
      typeof segment?.confidence === "number" && Number.isFinite(segment.confidence)
        ? clamp01(segment.confidence)
        : null,
    )
    .filter((value): value is number => value !== null);
  if (segmentConfidenceValues.length > 0) {
    const avg =
      segmentConfidenceValues.reduce((sum, value) => sum + value, 0) / segmentConfidenceValues.length;
    return { confidence: clamp01(avg), reason: "segment_average" };
  }
  const text = args.transcript.trim();
  if (!text) return { confidence: 0, reason: "empty_text" };
  let score = 0.5;
  if (text.length >= 20) score += 0.12;
  if (text.length >= 56) score += 0.12;
  if (/[.!?]["')\]]?$/.test(text)) score += 0.08;
  if (/\b(and|but|or|because|so)\s*$/i.test(text)) score -= 0.08;
  if (/[\u0000-\u001Fï¿½]/.test(text)) score -= 0.24;
  const normalized = text.replace(/\s+/g, "");
  if (normalized.length > 0) {
    const alnum = (normalized.match(/[A-Za-z0-9]/g) ?? []).length;
    const ratio = alnum / normalized.length;
    if (ratio < 0.45) score -= 0.12;
    if (ratio > 0.85) score += 0.04;
  }
  return { confidence: clamp01(score), reason: "heuristic_text_quality" };
}

export function shouldRequireTranscriptConfirmation(args: {
  confidence: number;
  translationUncertain: boolean;
  providerNeedsConfirmation?: boolean;
  minConfidence?: number;
}): boolean {
  if (args.providerNeedsConfirmation === true) return true;
  if (args.translationUncertain) return true;
  const minConfidence =
    typeof args.minConfidence === "number" && Number.isFinite(args.minConfidence)
      ? clamp01(args.minConfidence)
      : VOICE_STT_CONFIRM_THRESHOLD;
  return args.confidence < minConfidence;
}

function normalizeVoiceConfirmDispatchState(
  dispatchState?: "auto" | "confirm" | "blocked" | null,
): "auto" | "confirm" | "blocked" {
  if (dispatchState === "auto" || dispatchState === "blocked" || dispatchState === "confirm") {
    return dispatchState;
  }
  return "confirm";
}

function isLowPivotBlocked(
  pivotConfidence?: number | null,
  translationRiskHigh?: boolean,
): TranscriptConfirmPolicyReason | null {
  if (
    translationRiskHigh &&
    typeof pivotConfidence === "number" &&
    Number.isFinite(pivotConfidence) &&
    pivotConfidence < VOICE_TRANSCRIPT_AUTO_CONFIRM_BLOCK_PIVOT_CONFIDENCE
  ) {
    return "pivot_low_confidence";
  }
  if (
    translationRiskHigh &&
    (typeof pivotConfidence !== "number" ||
      !Number.isFinite(pivotConfidence) ||
      pivotConfidence < VOICE_TRANSCRIPT_AUTO_CONFIRM_BLOCK_PIVOT_CONFIDENCE)
  ) {
    return "translation_uncertain_without_pivot";
  }
  return null;
}

export function resolveTranscriptConfirmPolicy(args: {
  dispatchState?: "auto" | "confirm" | "blocked" | null;
  confidence: number;
  pivotConfidence?: number | null;
  translationUncertain: boolean;
  sourceLanguage?: string | null;
  sourceText?: string | null;
  translated?: boolean;
  lowAudioQuality?: boolean;
  speechActive?: boolean;
  queuedSegmentCount?: number;
}): TranscriptConfirmPolicyDecision {
  const dispatchState = normalizeVoiceConfirmDispatchState(args.dispatchState);
  if (dispatchState === "blocked") {
    return {
      action: "blocked",
      reason: "dispatch_blocked",
      confirmAutoEligible: false,
      confirmBlockReason: "dispatch_blocked",
    };
  }
  const translationRiskHigh = isHighRiskTranslationContext({
    translationUncertain: args.translationUncertain,
    sourceLanguage: args.sourceLanguage ?? null,
    sourceText: args.sourceText ?? null,
    translated: args.translated ?? false,
  });
  const pivotBlock = isLowPivotBlocked(args.pivotConfidence, translationRiskHigh);
  if (pivotBlock) {
    return {
      action: "blocked",
      reason: pivotBlock,
      confirmAutoEligible: false,
      confirmBlockReason: pivotBlock,
    };
  }
  if (dispatchState !== "confirm") {
    return {
      action: "manual_confirm",
      reason: "dispatch_not_confirm",
      confirmAutoEligible: false,
      confirmBlockReason: null,
    };
  }
  if (!(args.confidence > 0)) {
    return {
      action: "manual_confirm",
      reason: "invalid_confidence",
      confirmAutoEligible: false,
      confirmBlockReason: null,
    };
  }
  if (args.lowAudioQuality === true) {
    const strongConfidence = args.confidence >= Math.max(VOICE_STT_CONFIRM_THRESHOLD + 0.16, 0.74);
    if (translationRiskHigh || !strongConfidence) {
      return {
        action: "manual_confirm",
        reason: "low_audio_quality",
        confirmAutoEligible: false,
        confirmBlockReason: null,
      };
    }
  }
  if (args.speechActive === true || (args.queuedSegmentCount ?? 0) > 0) {
    return {
      action: "manual_confirm",
      reason: "live_activity",
      confirmAutoEligible: false,
      confirmBlockReason: null,
    };
  }
  return {
    action: "auto_confirm",
    reason: "eligible",
    confirmAutoEligible: true,
    confirmBlockReason: null,
  };
}

export function shouldAutoConfirmTranscriptPrompt(args: {
  dispatchState?: "auto" | "confirm" | "blocked" | null;
  confidence: number;
  languageConfidence?: number | null;
  pivotConfidence?: number | null;
  translationUncertain: boolean;
  sourceLanguage?: string | null;
  sourceText?: string | null;
  translated?: boolean;
  lowAudioQuality?: boolean;
  speechActive?: boolean;
  queuedSegmentCount?: number;
}): boolean {
  return resolveTranscriptConfirmPolicy({
    dispatchState: args.dispatchState,
    confidence: args.confidence,
    pivotConfidence: args.pivotConfidence,
    translationUncertain: args.translationUncertain,
    sourceLanguage: args.sourceLanguage,
    sourceText: args.sourceText,
    translated: args.translated,
    lowAudioQuality: args.lowAudioQuality,
    speechActive: args.speechActive,
    queuedSegmentCount: args.queuedSegmentCount,
  }).confirmAutoEligible;
}

function deriveVoiceSegmentLocalAnalysis(args: {
  sampleCount: number;
  speechProbabilitySum: number;
  snrDbSum: number;
  centroidSum: number;
  zcrSum: number;
  rmsDbSum: number;
  durationMs: number;
  minDurationMs?: number;
  minSpeechProbability?: number;
  minSnrDb?: number;
}): VoiceSegmentLocalAnalysis {
  if (args.sampleCount <= 0) {
    return {
      speechProbability: 0,
      snrDb: -20,
      centroid: 0,
      zcr: 0,
      rmsDb: -120,
      lowQuality: true,
    };
  }
  const speechProbability = clamp01(args.speechProbabilitySum / args.sampleCount);
  const snrDb = args.snrDbSum / args.sampleCount;
  const centroid = clamp01(args.centroidSum / args.sampleCount);
  const zcr = clamp01(args.zcrSum / args.sampleCount);
  const rmsDb = args.rmsDbSum / args.sampleCount;
  const minDurationMs = args.minDurationMs ?? VOICE_LOCAL_AUDIO_GATE_MIN_DURATION_MS;
  const minSpeechProbability = args.minSpeechProbability ?? VOICE_LOCAL_AUDIO_GATE_MIN_SPEECH_PROBABILITY;
  const minSnrDb = args.minSnrDb ?? VOICE_LOCAL_AUDIO_GATE_MIN_SNR_DB;
  const hardLowSignal =
    args.durationMs >= minDurationMs &&
    (speechProbability < minSpeechProbability || snrDb < minSnrDb);
  return {
    speechProbability,
    snrDb,
    centroid,
    zcr,
    rmsDb,
    lowQuality: hardLowSignal,
  };
}

function resolveSpeakerFromSessionProfiles(args: {
  analysis: VoiceSegmentLocalAnalysis;
  profiles: VoiceSessionSpeakerProfile[];
}): { speakerId: string; speakerConfidence: number; profileIndex: number } {
  const toVector = (profile: Pick<VoiceSessionSpeakerProfile, "centroidMean" | "zcrMean" | "rmsDbMean">) => ({
    centroid: profile.centroidMean,
    zcr: profile.zcrMean,
    rmsDbNorm: clamp01((profile.rmsDbMean + 80) / 80),
  });
  const analysisVector = {
    centroid: args.analysis.centroid,
    zcr: args.analysis.zcr,
    rmsDbNorm: clamp01((args.analysis.rmsDb + 80) / 80),
  };
  let bestIndex = -1;
  let bestDistance = Number.POSITIVE_INFINITY;
  for (let index = 0; index < args.profiles.length; index += 1) {
    const profile = args.profiles[index];
    const vector = toVector(profile);
    const distance = Math.sqrt(
      Math.pow(vector.centroid - analysisVector.centroid, 2) * 1.2 +
        Math.pow(vector.zcr - analysisVector.zcr, 2) * 0.9 +
        Math.pow(vector.rmsDbNorm - analysisVector.rmsDbNorm, 2),
    );
    if (distance < bestDistance) {
      bestDistance = distance;
      bestIndex = index;
    }
  }
  if (bestIndex >= 0 && bestDistance <= VOICE_SESSION_SPEAKER_MATCH_DISTANCE) {
    return {
      speakerId: args.profiles[bestIndex]!.id,
      speakerConfidence: clamp01(1 - bestDistance / VOICE_SESSION_SPEAKER_MATCH_DISTANCE),
      profileIndex: bestIndex,
    };
  }
  return {
    speakerId: `speaker_${args.profiles.length + 1}`,
    speakerConfidence: 0.54,
    profileIndex: -1,
  };
}

export function parseTranscriptConfirmationVoiceCommand(
  transcript: string,
): "confirm" | "retry" | "cancel" | null {
  const normalized = transcript
    .toLowerCase()
    .replace(/[^a-z0-9'\s]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!normalized) return null;
  const tokenCount = normalized.split(" ").filter(Boolean).length;
  if (tokenCount > 4) return null;
  if (
    normalized === "confirm" ||
    normalized === "yes" ||
    normalized === "yeah" ||
    normalized === "yep" ||
    normalized === "correct" ||
    normalized === "thats right" ||
    normalized === "that's right" ||
    normalized === "proceed"
  ) {
    return "confirm";
  }
  if (
    normalized === "retry" ||
    normalized === "again" ||
    normalized === "redo" ||
    normalized === "try again" ||
    normalized === "no" ||
    normalized === "nope" ||
    normalized === "wrong" ||
    normalized === "not that"
  ) {
    return "retry";
  }
  if (normalized === "cancel" || normalized === "dismiss" || normalized === "stop") {
    return "cancel";
  }
  return null;
}

export function normalizeVoiceCommandLaneEnvelope(
  payload: VoiceCommandLaneEnvelope | null | undefined,
): VoiceCommandLaneEnvelope | null {
  if (!payload || typeof payload !== "object") return null;
  const decision =
    payload.decision === "accepted" || payload.decision === "suppressed" || payload.decision === "none"
      ? payload.decision
      : null;
  if (!decision) return null;
  const action =
    payload.action === "send" || payload.action === "cancel" || payload.action === "retry"
      ? payload.action
      : null;
  const source =
    payload.source === "parser" || payload.source === "evaluator" || payload.source === "none"
      ? payload.source
      : "none";
  const suppressionReason =
    payload.suppression_reason === "disabled" ||
    payload.suppression_reason === "kill_switch" ||
    payload.suppression_reason === "rollout_inactive" ||
    payload.suppression_reason === "audio_quality_low" ||
    payload.suppression_reason === "strict_prefix_required" ||
    payload.suppression_reason === "log_only"
      ? payload.suppression_reason
      : null;
  const confidence =
    typeof payload.confidence === "number" && Number.isFinite(payload.confidence)
      ? clamp01(payload.confidence)
      : null;
  const utteranceId = typeof payload.utterance_id === "string" && payload.utterance_id.trim()
    ? payload.utterance_id.trim()
    : `vcmd:${crypto.randomUUID()}`;
  return {
    version:
      typeof payload.version === "string" && payload.version.trim()
        ? payload.version.trim()
        : "helix.voice.command_lane.v1",
    decision,
    action,
    confidence,
    source,
    suppression_reason: suppressionReason,
    strict_prefix_applied: payload.strict_prefix_applied === true,
    confirm_required: payload.confirm_required === true,
    utterance_id: utteranceId,
  };
}

export function describeVoiceCommandAction(action: "send" | "cancel" | "retry"): string {
  if (action === "send") return "Send current draft";
  if (action === "retry") return "Retry previous ask";
  return "Cancel pending flow";
}

export function scoreVoiceTurnComplete(input: {
  transcript: string;
  pauseMs: number;
  stability: number;
}): TurnCompleteScore {
  const text = input.transcript.trim();
  const completion = scoreConversationCompletion({
    transcript: text,
    pauseMs: input.pauseMs,
    stability: input.stability,
  });
  let score = completion.score;
  const hasTerminalPunctuation = /[.!?]["')\]]?$/.test(text);
  const trailingConnector = /\b(and|but|or|because|so|which|that|if|when|while|to)\s*$/i.test(text);
  const trailingQuestionStem =
    /\b(how|why|what|where|when|who)\s+(does|do|is|are|can|could|would|will|did)?\s*$/i.test(text);
  const unresolvedReferent =
    /\b(this|that|it|they|those|these)\b/i.test(text) && !/\b(is|are|was|were|means|refers|comes)\b/i.test(text);
  const shortTurn = text.split(/\s+/).filter(Boolean).length < 5;
  if (hasTerminalPunctuation) score += 0.05;
  if (trailingConnector) score -= 0.12;
  if (trailingQuestionStem) score -= 0.16;
  if (unresolvedReferent) score -= 0.08;
  if (shortTurn) score -= 0.08;
  score = clamp01(score);
  if (score >= VOICE_TURN_COMPLETE_HIGH_THRESHOLD) {
    return { score, band: "high", reason: "lexical_closure_high" };
  }
  if (score >= VOICE_TURN_COMPLETE_MEDIUM_THRESHOLD) {
    return { score, band: "medium", reason: "likely_continuation_hold" };
  }
  return { score, band: "low", reason: "incomplete_turn_hold" };
}

function extractIntentTerms(text: string, maxTerms = 8): string[] {
  return text
    .toLowerCase()
    .split(/[^a-z0-9]+/)
    .filter((token) => token.length >= 4)
    .slice(0, maxTerms);
}

export function scoreIntentShift(args: {
  activePrompt: string;
  nextTranscript: string;
}): IntentShiftScore {
  const prevTerms = new Set(extractIntentTerms(args.activePrompt, 16));
  const nextTerms = new Set(extractIntentTerms(args.nextTranscript, 16));
  if (nextTerms.size === 0) {
    return { score: 0, band: "continuation", reason: "no_terms" };
  }
  let overlap = 0;
  for (const term of nextTerms) {
    if (prevTerms.has(term)) overlap += 1;
  }
  const union = new Set([...prevTerms, ...nextTerms]).size || 1;
  const jaccard = overlap / union;
  const explicitShift =
    /\b(new topic|different topic|switch|instead|unrelated|another question)\b/i.test(
      args.nextTranscript.trim().toLowerCase(),
    );
  const score = clamp01((1 - jaccard) * 0.82 + (explicitShift ? 0.26 : 0));
  if (score >= 0.56) {
    return { score, band: "shift", reason: explicitShift ? "explicit_topic_shift" : "semantic_shift" };
  }
  return { score, band: "continuation", reason: "semantic_continuation" };
}

export type VoiceReasoningResponseAuthorityDecision = {
  suppress: boolean;
  reason:
    | "ok"
    | "continuation_merged"
    | "stale_prompt"
    | "phase_not_sealed"
    | "seal_token_mismatch"
    | "sealed_revision_mismatch"
    | "dispatch_hash_mismatch"
    | "inactive_attempt";
  restart: boolean;
};

export function evaluateVoiceReasoningResponseAuthority(args: {
  source: ReasoningAttemptSource;
  continuationRestartRequested: boolean;
  latestAskPromptForAttempt: string;
  askPromptForRequest: string;
  latestAttemptStatus?: ReasoningAttemptStatus;
  requestIntentRevision?: number;
  latestIntentRevision?: number;
  latestAttemptIntentRevision?: number;
  requestDispatchPromptHash?: string | null;
  latestDispatchPromptHash?: string | null;
  attemptTranscriptRevision?: number | null;
  latestSealedTranscriptRevision?: number | null;
  attemptSealToken?: string | null;
  latestSealToken?: string | null;
  assemblerPhase?: VoiceTurnAssemblerPhase | null;
}): VoiceReasoningResponseAuthorityDecision {
  if (args.continuationRestartRequested) {
    return { suppress: true, reason: "continuation_merged", restart: true };
  }
  if (
    args.latestAttemptStatus === "suppressed" ||
    args.latestAttemptStatus === "cancelled" ||
    args.latestAttemptStatus === "failed"
  ) {
    return { suppress: true, reason: "inactive_attempt", restart: false };
  }
  if (
    args.latestAskPromptForAttempt.length > 0 &&
    args.latestAskPromptForAttempt !== args.askPromptForRequest.trim()
  ) {
    return { suppress: true, reason: "stale_prompt", restart: true };
  }
  if (args.source !== "voice_auto") {
    return { suppress: false, reason: "ok", restart: false };
  }
  if (args.assemblerPhase && args.assemblerPhase !== "sealed") {
    return { suppress: true, reason: "phase_not_sealed", restart: false };
  }
  const attemptTranscriptRevision =
    typeof args.attemptTranscriptRevision === "number" && Number.isFinite(args.attemptTranscriptRevision)
      ? Math.max(0, Math.floor(args.attemptTranscriptRevision))
      : null;
  const latestSealedTranscriptRevision =
    typeof args.latestSealedTranscriptRevision === "number" &&
    Number.isFinite(args.latestSealedTranscriptRevision)
      ? Math.max(0, Math.floor(args.latestSealedTranscriptRevision))
      : null;
  if (
    attemptTranscriptRevision !== null &&
    latestSealedTranscriptRevision !== null &&
    attemptTranscriptRevision !== latestSealedTranscriptRevision
  ) {
    return { suppress: true, reason: "sealed_revision_mismatch", restart: false };
  }
  const attemptSealToken = args.attemptSealToken?.trim() || null;
  const latestSealToken = args.latestSealToken?.trim() || null;
  if (attemptSealToken && latestSealToken && attemptSealToken !== latestSealToken) {
    return { suppress: true, reason: "seal_token_mismatch", restart: false };
  }
  const requestIntentRevision =
    typeof args.requestIntentRevision === "number" && Number.isFinite(args.requestIntentRevision)
      ? args.requestIntentRevision
      : null;
  const latestIntentRevision =
    typeof args.latestIntentRevision === "number" && Number.isFinite(args.latestIntentRevision)
      ? args.latestIntentRevision
      : null;
  const latestAttemptIntentRevision =
    typeof args.latestAttemptIntentRevision === "number" &&
    Number.isFinite(args.latestAttemptIntentRevision)
      ? args.latestAttemptIntentRevision
      : null;
  if (
    requestIntentRevision !== null &&
    latestAttemptIntentRevision !== null &&
    requestIntentRevision !== latestAttemptIntentRevision
  ) {
    return { suppress: true, reason: "sealed_revision_mismatch", restart: true };
  }
  if (
    requestIntentRevision !== null &&
    latestIntentRevision !== null &&
    requestIntentRevision < latestIntentRevision
  ) {
    return { suppress: true, reason: "sealed_revision_mismatch", restart: true };
  }
  if (
    latestAttemptIntentRevision !== null &&
    latestIntentRevision !== null &&
    latestAttemptIntentRevision < latestIntentRevision
  ) {
    return { suppress: true, reason: "sealed_revision_mismatch", restart: true };
  }
  const requestDispatchPromptHash = args.requestDispatchPromptHash?.trim() || null;
  const latestDispatchPromptHash = args.latestDispatchPromptHash?.trim() || null;
  if (
    requestDispatchPromptHash !== null &&
    latestDispatchPromptHash !== null &&
    requestDispatchPromptHash !== latestDispatchPromptHash
  ) {
    return { suppress: true, reason: "dispatch_hash_mismatch", restart: true };
  }
  return { suppress: false, reason: "ok", restart: false };
}

function resolveVoiceAuthoritySuppression(
  reason: VoiceReasoningResponseAuthorityDecision["reason"],
): {
  suppressionReason: string;
  suppressionCause: string;
  restartDetail: string;
} {
  switch (reason) {
    case "ok":
      return {
        suppressionReason: "voice_turn_response_inactive_attempt",
        suppressionCause: "inactive_attempt",
        restartDetail: "inactive_attempt; restarting",
      };
    case "continuation_merged":
      return {
        suppressionReason: "voice_turn_continuation_merged",
        suppressionCause: "dispatch_hash_mismatch",
        restartDetail: "dispatch_hash_mismatch; restarting",
      };
    case "phase_not_sealed":
      return {
        suppressionReason: "voice_turn_response_phase_not_sealed",
        suppressionCause: "phase_not_sealed",
        restartDetail: "phase_not_sealed; restarting",
      };
    case "seal_token_mismatch":
      return {
        suppressionReason: "voice_turn_response_seal_token_mismatch",
        suppressionCause: "seal_token_mismatch",
        restartDetail: "seal_token_mismatch; restarting",
      };
    case "sealed_revision_mismatch":
      return {
        suppressionReason: "voice_turn_response_sealed_revision_mismatch",
        suppressionCause: "sealed_revision_mismatch",
        restartDetail: "sealed_revision_mismatch; restarting",
      };
    case "dispatch_hash_mismatch":
      return {
        suppressionReason: "voice_turn_response_dispatch_hash_mismatch",
        suppressionCause: "dispatch_hash_mismatch",
        restartDetail: "dispatch_hash_mismatch; restarting",
      };
    case "stale_prompt":
      return {
        suppressionReason: "voice_turn_response_stale_prompt",
        suppressionCause: "dispatch_hash_mismatch",
        restartDetail: "dispatch_hash_mismatch; restarting",
      };
    case "inactive_attempt":
      return {
        suppressionReason: "voice_turn_response_inactive_attempt",
        suppressionCause: "inactive_attempt",
        restartDetail: "inactive_attempt; restarting",
      };
    default:
      return {
        suppressionReason: "voice_turn_response_suppressed",
        suppressionCause: "inactive_attempt",
        restartDetail: "inactive_attempt; restarting",
      };
  }
}

export function shouldDispatchReasoningAttempt(transcript: string): boolean {
  const normalized = transcript.trim().toLowerCase();
  if (!normalized) return false;
  const text = normalized
    .replace(/^(?:(?:ok(?:ay)?)|yeah|yep|nope|thanks|thank you|cool|nice|right|well|so|um|uh)\b[,\s:-]*/g, "")
    .trim();
  const effective = text || normalized;
  if (effective.length < 14) return false;
  if (/^(ok|okay|yeah|yep|nope|thanks|thank you|cool|nice|right)\b$/.test(effective)) return false;
  const hasCodebaseCue =
    /\b(codebase|code base|repo|repository|source code|file|files|module|function|class|route|api)\b/.test(
      effective,
    );
  const hasTechnicalTopicCue = /\b(warp bubble|alcubierre|casimir|helix|retrieval)\b/.test(effective);
  const hasQuestionWordAnywhere = /\b(what|how|why|where|which|who|when)\b/.test(effective);
  const hasSolveOrDefinitionCue = /\b(full solve|solve|solved|definition|define|defined|explain)\b/.test(
    effective,
  );
  const hasVerificationCue = /\b(verify|prove|check|pass fail|certificate|integrity|evidence|risk|decision)\b/.test(
    effective,
  );
  const hasExecutionCue = /\b(implement|fix|change|update|remove|add|create|run|patch|deploy|execute)\b/.test(
    effective,
  );
  const hasMonitoringCue = /\b(what changed|status|monitor|state|watch)\b/.test(effective);
  const hasOperationalCue = hasVerificationCue || hasExecutionCue || hasMonitoringCue;
  if (
    (hasQuestionWordAnywhere || hasSolveOrDefinitionCue || effective.includes("?")) &&
    (hasCodebaseCue || hasTechnicalTopicCue)
  ) {
    return true;
  }
  if (hasOperationalCue) {
    return true;
  }
  const hasReasoningFramingCue = /\b(how|why|explain|define|walk me through|full solve|tell me about|break down|understand)\b/.test(
    effective,
  );
  if (hasReasoningFramingCue && (hasCodebaseCue || hasTechnicalTopicCue || hasSolveOrDefinitionCue)) {
    return true;
  }
  if (
    effective.includes("?") &&
    effective.length >= 16 &&
    (hasCodebaseCue || hasTechnicalTopicCue || hasSolveOrDefinitionCue || hasOperationalCue)
  ) {
    return true;
  }
  return false;
}

export function inferSuppressionCauseFromRouteReason(routeReasonCode?: string | null): string | null {
  const normalized = (routeReasonCode ?? "").trim().toLowerCase();
  if (!normalized) return null;
  if (!normalized.startsWith("suppressed:")) return null;
  const reason = normalized.slice("suppressed:".length).trim();
  if (!reason) return null;
  if (reason === "heuristic_low_salience") return "low_salience";
  if (reason === "clarify_after_attempt1") return "clarifier_requested";
  if (reason === "multilang_dispatch_blocked") return "multilang_dispatch_blocked";
  if (reason === "multilang_confirmation_required") return "multilang_confirmation_required";
  if (reason === "filler") return "filler";
  if (reason === "low_salience") return "low_salience";
  return `suppressed_${reason.replace(/[^a-z0-9_:-]+/g, "_")}`;
}

export function deriveVoiceTimelineSuppressionMeta(args: {
  status: HelixTimelineEntry["status"];
  type: HelixTimelineEntryType;
  detail?: string | null;
  meta?: Record<string, unknown> | null;
}): {
  suppressionCause: string | null;
  authorityRejectStage: "preflight" | "stream" | "final" | null;
} {
  const meta = args.meta ?? {};
  const detailLower = `${args.detail ?? ""}`.trim().toLowerCase();
  const explicitSuppressionCause =
    typeof meta.suppressionCause === "string" && meta.suppressionCause.trim()
      ? meta.suppressionCause.trim()
      : null;
  const routeSuppressionCause = inferSuppressionCauseFromRouteReason(
    typeof meta.routeReasonCode === "string" ? meta.routeReasonCode : null,
  );
  let suppressionCause = explicitSuppressionCause ?? routeSuppressionCause;

  if (!suppressionCause) {
    if (
      detailLower.includes("phase_not_sealed") ||
      detailLower.includes("seal_token_mismatch") ||
      detailLower.includes("sealed_revision_mismatch") ||
      detailLower.includes("dispatch_hash_mismatch") ||
      detailLower.includes("inactive_attempt")
    ) {
      if (detailLower.includes("phase_not_sealed")) suppressionCause = "phase_not_sealed";
      else if (detailLower.includes("seal_token_mismatch")) suppressionCause = "seal_token_mismatch";
      else if (detailLower.includes("sealed_revision_mismatch")) suppressionCause = "sealed_revision_mismatch";
      else if (detailLower.includes("dispatch_hash_mismatch")) suppressionCause = "dispatch_hash_mismatch";
      else suppressionCause = "inactive_attempt";
    } else if (detailLower.includes("superseded by newer")) {
      suppressionCause = "inactive_attempt";
    } else if (detailLower.includes("artifact-dominated") || detailLower.includes("artifact guard")) {
      suppressionCause = "artifact_guard_restart";
    } else if (detailLower.includes("clarifier requested")) {
      suppressionCause = "clarifier_requested";
    } else if (detailLower.includes("escalat")) {
      suppressionCause = "escalation_restart";
    } else if (args.status === "suppressed") {
      suppressionCause = "suppressed_unspecified";
    }
  }

  const explicitAuthorityRejectStage =
    meta.authorityRejectStage === "preflight" ||
    meta.authorityRejectStage === "stream" ||
    meta.authorityRejectStage === "final"
      ? meta.authorityRejectStage
      : null;
  const authorityRejectStage =
    explicitAuthorityRejectStage ?? (suppressionCause ? (args.type === "reasoning_stream" ? "stream" : "final") : null);

  return {
    suppressionCause: suppressionCause ?? null,
    authorityRejectStage,
  };
}

export function isStrongQuestionDispatchCandidate(transcript: string): boolean {
  const normalized = transcript.trim().toLowerCase();
  if (!normalized || normalized.length < 18) return false;
  if (isLowInformationTailTranscript(normalized)) return false;
  const words = normalized.split(/\s+/).filter(Boolean);
  if (words.length < 5) return false;
  const normalizedLeadStripped = normalized
    .replace(/^(?:(?:and|so|then|well|okay|ok)|you know|you found)\b[,\s:-]*/g, "")
    .trim();
  const startsWithQuestionWord =
    /^(what|how|why|where|which|who|when|can|could|would|should|is|are|do|does|did)\b/.test(
      normalizedLeadStripped || normalized,
    );
  const hasQuestionPunctuation = normalized.includes("?");
  const hasEmbeddedQuestionCue = /\b(what|how|why|where|which|who|when)\b/.test(normalized);
  const hasSolveOrDefinitionCue = /\b(full solve|solve|solved|definition|define|defined|explain)\b/.test(
    normalized,
  );
  if (!startsWithQuestionWord && !hasQuestionPunctuation && !hasEmbeddedQuestionCue && !hasSolveOrDefinitionCue) {
    return false;
  }
  const hasCodebaseCue =
    /\b(codebase|code base|repo|repository|source code|file|files|module|function|class|route|api)\b/.test(
      normalized,
    );
  const hasTechnicalTopicCue = /\b(warp bubble|alcubierre|casimir|helix|retrieval)\b/.test(normalized);
  return hasCodebaseCue || hasTechnicalTopicCue;
}

function isSimpleDirectPromptLaneCandidate(transcript: string): boolean {
  const text = String(transcript ?? "").trim().toLowerCase();
  if (!text) return false;
  if (text.length > 160) return false;
  const titleCue =
    /\b(?:title|name)\b/.test(text) &&
    /\b(?:paper|doc|document)\b/.test(text);
  const tinyDocCue =
    /\b(?:what(?:'s| is)?|show|give|tell)\b/.test(text) &&
    /\b(?:this|current)\s+(?:paper|doc|document)\b/.test(text) &&
    /\b(?:title|name|path)\b/.test(text);
  const quickDocExplainCue =
    /\b(?:what(?:'s| is)?|tell|give|explain|summar(?:y|ize))\b/.test(text) &&
    /\b(?:this|current)\s+(?:paper|doc|document)\b/.test(text) &&
    /\b(?:about|summary|summar(?:y|ize)|explain|mean|contains)\b/.test(text);
  const heavyReasoningCue =
    /\b(?:derive|proof|equation|compare|tradeoff|audit|review|call chain|implementation|refactor|design|architecture)\b/
      .test(text);
  if (heavyReasoningCue) return false;
  return titleCue || tinyDocCue || quickDocExplainCue;
}

function isSimpleTitleOrPathOnlyPrompt(transcript: string): boolean {
  const text = String(transcript ?? "").trim().toLowerCase();
  if (!text) return false;
  const titleCue =
    /\b(?:title|name)\b/.test(text) &&
    /\b(?:paper|doc|document)\b/.test(text);
  const pathCue =
    /\b(?:what(?:'s| is)?|show|give|tell)\b/.test(text) &&
    /\b(?:this|current)\s+(?:paper|doc|document)\b/.test(text) &&
    /\b(?:path)\b/.test(text);
  const quickTitleCue =
    /\b(?:what(?:'s| is)?|show|give|tell)\b/.test(text) &&
    /\b(?:this|current)\s+(?:paper|doc|document)\b/.test(text) &&
    /\b(?:title|name)\b/.test(text);
  return titleCue || pathCue || quickTitleCue;
}

function shouldQueueWorkspaceBackgroundReasoning(args: {
  transcript: string;
  docsViewerAnchorPath?: string | null;
}): boolean {
  const text = String(args.transcript ?? "").trim().toLowerCase();
  if (!text) return false;
  if (isSimpleTitleOrPathOnlyPrompt(text)) return false;
  if (/\b(?:background|in the background|while you continue)\b/.test(text)) return true;
  const workspaceCue =
    Boolean(args.docsViewerAnchorPath) ||
    /\b(?:docs?\s+viewer|workspace|repo|repository|codebase|source|file|path|paper|doc|document)\b/.test(
      text,
    );
  if (!workspaceCue) return false;
  const hardReasoningCue =
    /\b(?:verify|prove|proof|audit|compare|contrast|difference|tradeoff|synthesi[sz]e|integrity|evidence|claim|cross[-\s]?check)\b/.test(
      text,
    );
  return hardReasoningCue;
}

export function shouldForceObserveDispatchFromSuppression(args: {
  dispatchHint: boolean;
  routeReasonCode?: string | null;
  transcript: string;
}): boolean {
  if (args.dispatchHint) return false;
  const normalizedRoute = (args.routeReasonCode ?? "").trim().toLowerCase();
  const transcript = args.transcript.trim();
  if (transcript.length < 20) return false;
  if (isLowInformationTailTranscript(transcript)) return false;
  if (transcript.split(/\s+/).filter(Boolean).length < 4) return false;
  if (
    normalizedRoute === "suppressed:multilang_dispatch_blocked" ||
    normalizedRoute === "suppressed:multilang_confirmation_required"
  ) {
    return shouldDispatchReasoningAttempt(transcript) || isStrongQuestionDispatchCandidate(transcript);
  }
  if (shouldDispatchReasoningAttempt(transcript)) return true;
  return isStrongQuestionDispatchCandidate(transcript);
}

export function resolveSuppressedDispatchRescueTranscript(args: {
  dispatchHint: boolean;
  routeReasonCode?: string | null;
  transcript: string;
  draftText: string;
}): string | null {
  if (args.dispatchHint) return null;
  const routeReason = (args.routeReasonCode ?? "").trim().toLowerCase();
  const multilangSuppressed =
    routeReason === "suppressed:multilang_dispatch_blocked" ||
    routeReason === "suppressed:multilang_confirmation_required";
  const transcript = args.transcript.trim();
  const draftText = args.draftText.trim();
  if (!transcript || !draftText) return null;
  const transcriptWords = transcript.split(/\s+/).filter(Boolean).length;
  if (!isLowInformationTailTranscript(transcript) && transcriptWords >= 4) return null;
  if (draftText.length <= transcript.length + 8) return null;
  const transcriptLower = transcript.toLowerCase();
  const draftLower = draftText.toLowerCase();
  if (!draftLower.includes(transcriptLower) && !transcriptLower.includes(draftLower)) return null;
  const focusedDraft = extractLatestContinuationQuestionFocus(draftText) ?? draftText;
  const normalizedFocusedDraft = focusedDraft.trim();
  if (!normalizedFocusedDraft || normalizedFocusedDraft.length <= transcript.length + 8) return null;
  if (multilangSuppressed) {
    if (
      shouldDispatchReasoningAttempt(normalizedFocusedDraft) ||
      isStrongQuestionDispatchCandidate(normalizedFocusedDraft)
    ) {
      return clipText(normalizedFocusedDraft, 720);
    }
    return null;
  }
  if (
    !shouldDispatchReasoningAttempt(normalizedFocusedDraft) &&
    !isStrongQuestionDispatchCandidate(normalizedFocusedDraft)
  ) {
    return null;
  }
  return clipText(normalizedFocusedDraft, 720);
}

export function shouldMergePendingConfirmationTranscript(args: {
  pendingTranscript: string;
  nextTranscript: string;
  pendingAgeMs: number;
  windowMs?: number;
}): boolean {
  const pending = args.pendingTranscript.trim();
  const next = args.nextTranscript.trim();
  if (!pending || !next) return false;
  const windowMs = args.windowMs ?? VOICE_CONTINUATION_MERGE_WINDOW_MS;
  const safeGapMs = Number.isFinite(args.pendingAgeMs) ? Math.max(0, args.pendingAgeMs) : Number.POSITIVE_INFINITY;
  if (
    shouldMergeVoiceContinuationTurn({
      previousPrompt: pending,
      nextTranscript: next,
      gapMs: safeGapMs,
      windowMs,
    })
  ) {
    return true;
  }
  if (isLowInformationTailTranscript(next)) return true;
  if (!shouldDispatchReasoningAttempt(next)) return true;
  return false;
}

export function isLikelyContextDependentTurn(transcript: string): boolean {
  const normalized = transcript.trim().toLowerCase();
  if (!normalized) return false;
  if (normalized.length > 220) return false;
  if (
    /^(where|why|how|what)\s+(is|are|was|were|does|did)\s+(that|this|it|they|those|these)\b/.test(
      normalized,
    )
  ) {
    return true;
  }
  if (/^(and|so|then|also)\b/.test(normalized)) return true;
  if (/\b(that|this|it|they|those|these)\b/.test(normalized) && normalized.length <= 72) {
    return true;
  }
  return false;
}

function extractPriorUserContext(recentTurns: string[], currentTranscript?: string): string | null {
  const currentNormalized = currentTranscript?.trim().toLowerCase() || null;
  for (let index = recentTurns.length - 1; index >= 0; index -= 1) {
    const line = recentTurns[index]?.trim() ?? "";
    if (!line) continue;
    if (!/^user:/i.test(line)) continue;
    const text = line.replace(/^user:\s*/i, "").trim();
    if (!text) continue;
    if (currentNormalized && text.toLowerCase() === currentNormalized) continue;
    return text;
  }
  return null;
}

type VoiceTimelineBuildInfo = {
  clientBuild: string;
  clientMode: "dev" | "prod";
  serverService: string | null;
  serverVersion: string | null;
  serverGitSha: string | null;
  serverBuildTime: string | null;
  fetchedAtMs: number | null;
  error: string | null;
};

function resolveVoiceTimelineClientBuildStamp(): string {
  if (typeof window === "undefined") return "unknown";
  const win = window as Window & { __APP_WARP_BUILD?: string };
  const stamped = typeof win.__APP_WARP_BUILD === "string" ? win.__APP_WARP_BUILD.trim() : "";
  if (stamped) return stamped;
  return import.meta.env?.DEV ? "dev" : "prod";
}

function hasSufficientLexicalCarryover(nextTranscript: string, priorUserTurn: string): boolean {
  const nextTerms = new Set(extractIntentTerms(nextTranscript, 12));
  const priorTerms = new Set(extractIntentTerms(priorUserTurn, 14));
  if (nextTerms.size === 0 || priorTerms.size === 0) return false;
  let overlap = 0;
  for (const term of nextTerms) {
    if (!priorTerms.has(term)) continue;
    overlap += 1;
    if (overlap >= 2) return true;
  }
  return false;
}

export function isLikelyNearTurnContinuation(args: {
  transcript: string;
  priorUserTurn: string | null;
}): boolean {
  const normalized = args.transcript.trim().toLowerCase();
  const prior = args.priorUserTurn?.trim();
  if (!normalized || !prior) return false;
  if (
    /^(where|why|how|what)\s+(is|are|was|were|does|did)\s+(that|this|it|they|those|these)\b/.test(
      normalized,
    )
  ) {
    return true;
  }
  if (/^(and|so|then|also|but|because|which|that|right|yeah|yes|well)\b/.test(normalized)) return true;
  if (/^(it|this|that|they|those|these)\b/.test(normalized)) return true;
  return hasSufficientLexicalCarryover(normalized, prior.toLowerCase());
}

export function buildVoiceReasoningDispatchPrompt(args: {
  transcript: string;
  recentTurns: string[];
  explorationPacket?: ConversationExplorationPacket | null;
}): string {
  const transcript = args.transcript.trim();
  if (!transcript) return "";
  if (!isLikelyContextDependentTurn(transcript)) {
    return transcript;
  }
  const priorUser = extractPriorUserContext(args.recentTurns, transcript);
  if (!isLikelyNearTurnContinuation({ transcript, priorUserTurn: priorUser })) {
    return transcript;
  }
  const topicHint = args.explorationPacket?.topic?.trim() || priorUser || transcript;
  return [
    `Follow-up turn: ${transcript}`,
    `Immediate anchor: ${clipText(topicHint, 220)}`,
    "Use only this immediate anchor for continuity before answering.",
    priorUser ? `Prior user turn: ${clipText(priorUser, 220)}` : "",
  ]
    .filter(Boolean)
    .join("\n");
}

function normalizeConversationModeForDispatch(
  mode: "observe" | "act" | "verify" | "clarify" | undefined,
): "observe" | "act" | "verify" | undefined {
  if (!mode || mode === "clarify") return undefined;
  return mode;
}

type ExplorationLadderAction =
  | "finalize"
  | "restart_after_artifact"
  | "clarify_after_attempt1"
  | "escalate_verify"
  | "escalate_act";

type ExplorationLadderDecision = {
  action: ExplorationLadderAction;
  reasonCode: string;
};

function inferExplorationTopicKey(packet: ConversationExplorationPacket | null | undefined, prompt: string): string {
  const raw = (packet?.topic?.trim() || prompt.trim() || "unknown").toLowerCase();
  const normalized = raw.replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 80);
  return normalized || "unknown";
}

function buildExplorationEscalationPrompt(args: {
  mode: "verify" | "act";
  prompt: string;
  previousOutput: string;
  packet?: ConversationExplorationPacket | null;
}): string {
  const topic = clipText(args.packet?.topic?.trim() || args.prompt.trim(), 140);
  const previous = clipText(args.previousOutput.trim(), 700);
  if (args.mode === "verify") {
    return [
      `Topic: ${topic}`,
      "Run verify mode on this exploration thread.",
      "Return pass/fail with grounded evidence anchors and deterministic fail reason if blocked.",
      "",
      "Original user turn:",
      args.prompt.trim(),
      "",
      "Observe attempt output:",
      previous,
    ].join("\n");
  }
  return [
    `Topic: ${topic}`,
    "Run act mode on this exploration thread.",
    "Return concrete execution steps and expected receipts, bounded by existing safety gates.",
    "",
    "Original user turn:",
    args.prompt.trim(),
    "",
    "Observe attempt output:",
    previous,
  ].join("\n");
}

function buildExplorationArtifactRetryPrompt(args: {
  prompt: string;
  previousOutput: string;
  packet?: ConversationExplorationPacket | null;
}): string {
  const fileLocationPrompt = isRepoFileLocationRequestPrompt(args.prompt);
  const topic = clipText(args.packet?.topic?.trim() || args.prompt.trim(), 140);
  const previous = clipText(args.previousOutput.trim(), 700);
  return [
    `Topic: ${topic}`,
    "Restart observe mode from the top of the reasoning chain.",
    fileLocationPrompt
      ? "Avoid artifact-only templates and mission/ethos scaffolds; include concrete file paths only when they directly answer the user request."
      : "Do not emit repository file lists, mission/ethos scaffolds, or artifact-only templates.",
    "If the output drifts into mission/ethos ideology content without explicit user request, ask one focused clarifier instead of finalizing.",
    "Return a plain, grounded explanation aligned to the user turn. If still blocked, ask one focused clarifier.",
    "",
    "Original user turn:",
    args.prompt.trim(),
    "",
    "Previous artifact-dominated output (avoid repeating this pattern):",
    previous,
  ].join("\n");
}

function isExplorationArtifactRetryPrompt(promptText: string): boolean {
  const normalized = promptText.trim().toLowerCase();
  if (!normalized) return false;
  return (
    normalized.startsWith("topic:") &&
    normalized.includes("restart observe mode from the top of the reasoning chain.")
  );
}

function extractOriginalTurnFromExplorationArtifactRetryPrompt(promptText: string): string | null {
  const match =
    /(?:^|\n)\s*Original user turn:\s*\n([\s\S]*?)(?:\n\s*Previous artifact-dominated output|\n\s*$)/i.exec(
      promptText,
    );
  const extracted = match?.[1]?.trim() ?? "";
  return extracted || null;
}

export function resolveReasoningAttemptTimelineText(
  attempt: Pick<ReasoningAttempt, "source" | "prompt" | "recordedText">,
): string {
  const recordedText = typeof attempt.recordedText === "string" ? attempt.recordedText.trim() : "";
  if (recordedText) return recordedText;
  const prompt = attempt.prompt.trim();
  if (!prompt) return "";
  if (attempt.source !== "voice_auto") return prompt;
  if (!isExplorationArtifactRetryPrompt(prompt)) return prompt;
  return extractOriginalTurnFromExplorationArtifactRetryPrompt(prompt) ?? prompt;
}

function isRepoFileLocationRequestPrompt(promptText: string): boolean {
  const normalized = promptText.trim().toLowerCase();
  if (!normalized) return false;
  return /\b(file|files|filepath|file path|path|paths|codebase|repo|repository|source code|where|located|implemented|define[sd])\b/.test(
    normalized,
  );
}

export function decideExplorationLadderAction(args: {
  explorationAttemptCount: number;
  outputText: string;
  rawOutputText?: string;
  promptText?: string;
  failReason?: string | null;
  mode?: "observe" | "act" | "verify";
  debug?:
    | {
        arbiter_mode?: "repo_grounded" | "hybrid" | "general" | "clarify";
        coverage_gate_reason?: string;
        evidence_gate_ok?: boolean;
        verification_anchor_required?: boolean;
      }
    | null
    | undefined;
}): ExplorationLadderDecision {
  const trimmedText = args.outputText.trim();
  const rawText = (args.rawOutputText ?? trimmedText).trim();
  const normalizedText = trimmedText.toLowerCase();
  const normalizedFail = (args.failReason ?? "").trim().toLowerCase();
  const normalizedCoverage = (args.debug?.coverage_gate_reason ?? "").trim().toLowerCase();
  const normalizedPrompt = (args.promptText ?? "").trim().toLowerCase();
  const fileLocationPrompt = isRepoFileLocationRequestPrompt(args.promptText ?? "");
  const firstAttempt = args.explorationAttemptCount <= 1;
  const ideologyDomainLeak = isLikelyIdeologyDomainLeak({
    promptText: args.promptText,
    outputText: rawText || trimmedText,
  });
  const artifactDominated =
    isArtifactDominatedReasoningText(trimmedText) ||
    (rawText !== trimmedText && isArtifactDominatedReasoningText(rawText)) ||
    ideologyDomainLeak;
  const explicitClarifierQuestion =
    /\?$/.test(trimmedText) &&
    /\b(could you|can you|would you|please clarify|which|what specific|what context|provide)\b/.test(
      normalizedText,
    );
  const substantiveAnswer =
    normalizedText.length >= 180 ||
    /[.!]\s+/.test(normalizedText) ||
    /\b(warp bubble|general relativity|metric|space-time|mechanism|because|therefore)\b/.test(normalizedText);
  const sanitizedOutput = sanitizeReasoningOutputText(rawText || trimmedText);
  const sanitizedLower = sanitizedOutput.toLowerCase();
  const sanitizedSentenceHits = (sanitizedOutput.match(/[.!?](?:\s|$)/g) ?? []).length;
  const sanitizedSemanticHits = (
    sanitizedLower.match(
      /\b(?:is|are|means|refers|describes|involves|because|therefore|allows|helps|shows|occurs|happens)\b/gi,
    ) ?? []
  ).length;
  const promptTerms = new Set(extractIntentTerms(args.promptText ?? "", 14));
  let topicalOverlap = 0;
  if (promptTerms.size > 0) {
    for (const term of extractIntentTerms(sanitizedOutput, 20)) {
      if (!promptTerms.has(term)) continue;
      topicalOverlap += 1;
      if (topicalOverlap >= 2) break;
    }
  }
  const hardArtifactSignals = (
    /\b(?:tree walk|checked files|searched terms|focus anchor:|what_is_|how_they_connect:)\b/i.test(
      rawText || trimmedText,
    ) ||
    /\bwhat[\s_]?is[\s_](?:warp[\s_]?bubble|mission[\s_]?ethos)\s*:/i.test(rawText || trimmedText) ||
    /\bhow[\s_]?they[\s_]?connect\s*:/i.test(rawText || trimmedText) ||
    /\bconstraints?_and_falsifiability\s*:/i.test(rawText || trimmedText) ||
    hasRuntimeFallbackArtifactSpill(rawText || trimmedText)
  );
  const fileRefLikeHits = (
    (rawText || trimmedText).match(
      /\b(?:[A-Za-z]:[\\/]|(?:docs|client|server|shared|scripts|tests|configs|reports|artifacts|packages|sdk|cli)[\\/]|[A-Za-z0-9_.-]+\.(?:ts|tsx|js|jsx|md|json|yaml|yml))\S*/gi,
    ) ?? []
  ).length;
  const missingContextSignal =
    explicitClarifierQuestion ||
    /\b(please clarify|missing context|need more context|one more detail|specific problem|which context)\b/.test(
      normalizedText,
    ) ||
    /\bclarify\b/.test(normalizedFail) ||
    /\bmissing\b/.test(normalizedCoverage) ||
    (args.debug?.arbiter_mode === "clarify" && !substantiveAnswer);
  const salvageableArtifactAnswer =
    artifactDominated &&
    !hardArtifactSignals &&
    (
      (
        sanitizedOutput.length >= 180 &&
        sanitizedSentenceHits >= 2 &&
        sanitizedSemanticHits >= 4
      ) ||
      (args.explorationAttemptCount > 1 && substantiveAnswer && !missingContextSignal) ||
      (
        fileLocationPrompt &&
        fileRefLikeHits >= 1 &&
        sanitizedOutput.length >= 100 &&
        topicalOverlap >= 1 &&
        (sanitizedSentenceHits >= 1 || sanitizedSemanticHits >= 2)
      )
    );
  if (firstAttempt && missingContextSignal) {
    return { action: "clarify_after_attempt1", reasonCode: "suppressed:clarify_after_attempt1" };
  }

  // Restart observe lane from rung 1 for artifact output, bounded by retry cap.
  if (artifactDominated && args.mode !== "verify" && args.mode !== "act") {
    if (salvageableArtifactAnswer) {
      return { action: "finalize", reasonCode: "dispatch:observe_finalize" };
    }
    if (args.explorationAttemptCount < VOICE_ARTIFACT_RESTART_MAX_ATTEMPTS) {
      return { action: "restart_after_artifact", reasonCode: "dispatch:observe_restart_artifact_guard" };
    }
    return { action: "clarify_after_attempt1", reasonCode: "suppressed:clarify_after_artifact_retry_exhausted" };
  }

  const explicitVerifyIntent = /\b(verify|verification|prove|proof|validate|integrity|certificate|pass\/?fail|audit)\b/.test(
    normalizedPrompt,
  );
  const verifySignal =
    args.mode === "verify" ||
    args.debug?.verification_anchor_required === true ||
    explicitVerifyIntent;
  if (verifySignal) {
    return { action: "escalate_verify", reasonCode: "dispatch:verify" };
  }

  const explicitActIntent = /\b(implement|apply patch|edit files|run tool|execute|change code|update code|fix)\b/.test(
    normalizedPrompt,
  );
  const actSignal =
    args.mode === "act" ||
    explicitActIntent;
  if (actSignal) {
    return { action: "escalate_act", reasonCode: "dispatch:act" };
  }

  return { action: "finalize", reasonCode: "dispatch:observe_finalize" };
}

